(()=>{(function(){if(!window.WPSD)return;let t=document.createElement("style");t.textContent=".wpsd-pin-marker{transition:transform 0.15s ease;}.wpsd-pin-marker:hover{transform:scale(1.3);}.wpsd-badge{display:inline-block;padding:2px 8px;border-radius:12px;font-size:11px;font-weight:600;}.wpsd-badge-pending{background:#fef3c7;color:#92400e;}.wpsd-badge-approved{background:#dcfce7;color:#166534;}.wpsd-badge-rejected{background:#fee2e2;color:#991b1b;}.wpsd-badge-canceled{background:#f3f4f6;color:#374151;}.wpsd-badge-completed{background:#dbeafe;color:#1e40af;}.wpsd-pin-both{width:18px;height:18px;border-radius:50%;border:2px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.3);background:linear-gradient(135deg,#005247 50%,#e0b912 50%);}.wpsd-pin-act{width:18px;height:18px;border-radius:50%;border:2px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.3);background:#005247;}.wpsd-pin-acc{width:18px;height:18px;border-radius:50%;border:2px solid #fff;box-shadow:0 2px 6px rgba(0,0,0,0.3);background:#e0b912;}",document.head.appendChild(t),WPSD_Tabs.init(),WPSD_Modals.init();let i=document.querySelector(".wpsd-panel.is-active");if(i){let d=i.id.replace("wpsd-panel-","");WPSD_Tabs.loadTabIfNeeded(d)}document.querySelectorAll(".wpsd-tab").forEach(d=>{d.addEventListener("click",()=>setTimeout(()=>{let a=document.querySelector("#wpsd_carte_map"),o=document.querySelector("#wpsd_parcours_map");if(a&&a._leaflet_id){let e=Object.values(a).find(r=>r._leaflet_id);e&&e.invalidateSize()}if(o&&o._leaflet_id){let e=Object.values(o).find(r=>r._leaflet_id);e&&e.invalidateSize()}},200))})})();})();
